		tfResult = strings.ReplaceAll(tfResult, "%k", fmt.Sprintf("%d", tfH))
		tfResult = strings.ReplaceAll(tfResult, "%i", fmt.Sprintf("%02d", tfM))
		tfResult = strings.ReplaceAll(tfResult, "%S", fmt.Sprintf("%02d", tfSec))
		tfResult = strings.ReplaceAll(tfResult, "%s", fmt.Sprintf("%02d", tfSec))
