		// Simple CRC32 implementation
		crcS := toString(crcVal)
		var crcResult uint32 = 0xFFFFFFFF
		for ci := 0; ci < len(crcS); ci++ {
			crcResult ^= uint32(crcS[ci])
			for cj := 0; cj < 8; cj++ {
				if crcResult&1 != 0 {
					crcResult = (crcResult >> 1) ^ 0xEDB88320
				} else {
					crcResult >>= 1
				}
			}
		}
		return int64(crcResult ^ 0xFFFFFFFF), nil
